import { strict as assert } from "node:assert";

import { mulberry32 } from "../app/js/engine/prng.mjs";
import { lnFactorial, lnComb, hypergeomPmf, hypergeomSf } from "../app/js/engine/stats.mjs";
import { partitionTiers } from "../app/js/engine/comparison.mjs";

let total = 0;
let failed = 0;

function group(name, fn) {
  console.log(`\n=== ${name} ===`);
  try {
    fn();
  } catch (err) {
    failed++;
    total++;
    console.log(`  FAIL  ${err.message}`);
  }
}

function check(label, condition, detail = "") {
  total++;
  if (condition) {
    console.log(`  PASS  ${label}${detail ? "  " + detail : ""}`);
  } else {
    failed++;
    console.log(`  FAIL  ${label}${detail ? "  " + detail : ""}`);
  }
}

function approx(a, b, tol = 1e-9) {
  return Math.abs(a - b) <= tol;
}

// mulberry32: deterministic, period-≥-2³², sane distribution properties.
group("mulberry32 (PRNG)", () => {
  const r1 = mulberry32(42);
  const r2 = mulberry32(42);
  const seqA = Array.from({ length: 8 }, () => r1());
  const seqB = Array.from({ length: 8 }, () => r2());
  check("same seed → identical sequence", JSON.stringify(seqA) === JSON.stringify(seqB));

  const r3 = mulberry32(43);
  const seqC = Array.from({ length: 8 }, () => r3());
  check("different seed → different sequence", JSON.stringify(seqA) !== JSON.stringify(seqC));

  const r4 = mulberry32(0xDEADBEEF);
  let inRange = true;
  for (let i = 0; i < 1000; i++) {
    const v = r4();
    if (!(v >= 0 && v < 1)) { inRange = false; break; }
  }
  check("output is always in [0, 1)", inRange);

  const r5 = mulberry32(7);
  const N = 100_000;
  let sum = 0;
  for (let i = 0; i < N; i++) sum += r5();
  const mean = sum / N;
  check("uniform mean ≈ 0.5 over 100k draws", Math.abs(mean - 0.5) < 0.01, `(mean=${mean.toFixed(4)})`);
});

// lnFactorial: log-space factorial used by the hypergeometric PMF.
group("lnFactorial", () => {
  check("ln(0!) = 0", lnFactorial(0) === 0);
  check("ln(1!) = 0", lnFactorial(1) === 0);
  check("ln(5!) = ln(120)", approx(lnFactorial(5), Math.log(120)));
  check("ln(10!) = ln(3628800)", approx(lnFactorial(10), Math.log(3628800), 1e-9));
});

// lnComb: log-space binomial coefficient.
group("lnComb (log binomial coefficient)", () => {
  check("C(5, 0) = 1", approx(Math.exp(lnComb(5, 0)), 1));
  check("C(5, 5) = 1", approx(Math.exp(lnComb(5, 5)), 1));
  check("C(10, 3) = 120", approx(Math.exp(lnComb(10, 3)), 120, 1e-7));
  check("C(20, 10) = 184756", approx(Math.exp(lnComb(20, 10)), 184756, 1e-3));
  check("C(5, -1) = -∞ (out of range)", lnComb(5, -1) === -Infinity);
  check("C(5, 6) = -∞ (out of range)", lnComb(5, 6) === -Infinity);
});

// hypergeomPmf: probability of exactly k hits in n draws from urn(N, K).
group("hypergeomPmf", () => {
  // Closed-form sanity: P(X=2; N=10, K=5, n=5) = C(5,2)*C(5,3)/C(10,5) = 10*10/252 = 100/252.
  check("PMF closed-form: N=10,K=5,n=5,k=2",
    approx(hypergeomPmf(10, 5, 5, 2), 100 / 252, 1e-12));
  let sum = 0;
  for (let k = 0; k <= 5; k++) sum += hypergeomPmf(10, 5, 5, k);
  check("PMF sums to 1 over support", approx(sum, 1, 1e-12), `(sum=${sum})`);
});

// hypergeomSf: P(X >= k); used as the diagnostic "HG p" upper bound.
group("hypergeomSf", () => {
  check("SF(N=10, K=5, n=5, k=0) = 1", approx(hypergeomSf(10, 5, 5, 0), 1, 1e-12));
  check("SF(N=10, K=5, n=5, k=6) = 0 (above support)",
    approx(hypergeomSf(10, 5, 5, 6), 0, 1e-12));
  check("SF(N=10, K=5, n=5, k=5) = C(5,5)C(5,0)/C(10,5) = 1/252",
    approx(hypergeomSf(10, 5, 5, 5), 1 / 252, 1e-12));
  check("SF is monotonically non-increasing in k", (() => {
    let prev = Infinity;
    for (let k = 0; k <= 5; k++) {
      const v = hypergeomSf(10, 5, 5, k);
      if (v > prev + 1e-12) return false;
      prev = v;
    }
    return true;
  })());
  check("SF clamped to ≤ 1.0",
    hypergeomSf(10, 5, 5, 0) <= 1.0 && hypergeomSf(100, 50, 50, 0) <= 1.0);
});

// partitionTiers: tier-bucketing for the frequency-weighted circularity null.
// The T=3 branch must remain the legacy [⌈n/3⌉, ⌈n/3⌉, rest] split (canonical
// p-value depends on it). Other tier counts use even-out distribution.
group("partitionTiers", () => {
  const arr = (n) => Array.from({ length: n }, (_, i) => i);

  const t3a = partitionTiers(arr(9), 3);
  check("T=3 over n=9 → [3,3,3] (legacy)",
    JSON.stringify(t3a.map(t => t.length)) === JSON.stringify([3, 3, 3]));

  const t3b = partitionTiers(arr(10), 3);
  check("T=3 over n=10 → [4,4,2] (legacy ceil/ceil/rest)",
    JSON.stringify(t3b.map(t => t.length)) === JSON.stringify([4, 4, 2]));

  const t3c = partitionTiers(arr(43), 3);
  check("T=3 over n=43 → [15,15,13] (matches PRE_CIRCULARITY)",
    JSON.stringify(t3c.map(t => t.length)) === JSON.stringify([15, 15, 13]));

  // Other T: extras distributed front-loaded (even-out, no empty trailing tier).
  const t10 = partitionTiers(arr(43), 10);
  check("T=10 over n=43 → no empty tier (regression: naive-ceil bug)",
    t10.every(t => t.length > 0));
  check("T=10 over n=43 → totals match input length",
    t10.reduce((s, t) => s + t.length, 0) === 43);
  check("T=10 over n=43 → [5,5,5,4,4,4,4,4,4,4] (matches PRE_CIRCULARITY tierSweep)",
    JSON.stringify(t10.map(t => t.length)) === JSON.stringify([5, 5, 5, 4, 4, 4, 4, 4, 4, 4]));

  const t5 = partitionTiers(arr(43), 5);
  check("T=5 over n=43 → [9,9,9,8,8] (matches PRE_CIRCULARITY tierSweep)",
    JSON.stringify(t5.map(t => t.length)) === JSON.stringify([9, 9, 9, 8, 8]));

  const t2 = partitionTiers(arr(43), 2);
  check("T=2 over n=43 → [22,21] (matches PRE_CIRCULARITY tierSweep)",
    JSON.stringify(t2.map(t => t.length)) === JSON.stringify([22, 21]));

  // key extractor projects elements; verify it round-trips.
  const objs = [{ s: 1 }, { s: 2 }, { s: 3 }, { s: 4 }];
  const keyed = partitionTiers(objs, 2, x => x.s);
  check("key extractor applied to bucketed elements",
    JSON.stringify(keyed) === JSON.stringify([[1, 2], [3, 4]]));
});

console.log(`\n=== Summary: ${total - failed} passed, ${failed} failed ===`);
process.exit(failed > 0 ? 1 : 0);
